// ── Validate & normalise the incoming lead payload ──────────
const body = $input.first().json.body || $input.first().json;

// Pull every common field name a web form might send
const name    = body.name    || body.fullName  || body.full_name  || body.firstName || '';
const email   = body.email   || body.emailAddress || '';
const phone   = body.phone   || body.phoneNumber  || body.mobile   || '';
const company = body.company || body.companyName   || body.org      || '';
const subject = body.subject || body.projectType   || body.service  || 'General Inquiry';
const message = body.message || body.description   || body.notes    || '';
const source  = body.source  || body.utm_source    || 'Website Form';
const page    = body.page    || body.referrer      || body.pageUrl  || '';

// Basic validation
if (!email) throw new Error('Lead rejected: no email address provided');
if (!name)  throw new Error('Lead rejected: no name provided');

// Email format check
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) throw new Error('Lead rejected: invalid email format');

// Timestamp
const now       = new Date();
const timestamp = now.toISOString();
const dateStr   = now.toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });
const timeStr   = now.toLocaleTimeString('en-IN', { hour:'2-digit', minute:'2-digit', hour12:true });

// Detect if business email (not free providers)
const freeProviders = ['gmail.com','yahoo.com','hotmail.com','outlook.com','icloud.com','live.com'];
const emailDomain   = email.split('@')[1]?.toLowerCase() || '';
const isBusinessEmail = !freeProviders.includes(emailDomain);

// Simple lead score (0–100)
let score = 30; // base
if (isBusinessEmail) score += 20;
if (phone)           score += 15;
if (company)         score += 15;
if (message && message.length > 60) score += 10;
const urgentWords = ['urgent','asap','immediately','today','quote','pricing','demo','budget'];
if (urgentWords.some(w => (message + subject).toLowerCase().includes(w))) score += 10;

const grade = score >= 75 ? 'Hot' : score >= 50 ? 'Warm' : 'Cold';

return [{
  json: {
    // Lead fields
    name, email, phone, company, subject, message, source, page,
    // Meta
    timestamp, dateStr, timeStr,
    emailDomain, isBusinessEmail,
    // Scoring
    score, grade,
    // Row ID for Sheets
    leadId: `LEAD-${Date.now()}`
  }
}];

